{
var input = inputs.Length > 0 ? inputs[0] : null;
if (input == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var mode = GetChoice(parameters, "mode", "mirrorHorizontal");
var centerX = GetFloat(parameters, "centerX", 0.5f);
var centerY = GetFloat(parameters, "centerY", 0.5f);

var size = context.TileSize;
var result = new PixelBuffer(size, size);
var cx = centerX * size;
var cy = centerY * size;

result.ParallelForEachPixel((x, y) =>
{
    float sx, sy;

    switch (mode)
    {
        case "mirrorVertical":
            sx = x;
            sy = y < cy ? y : 2f * cy - y;
            break;
        case "mirrorDiagonal":
            sx = y;
            sy = x;
            break;
        case "mirrorQuad":
            sx = x < cx ? x : 2f * cx - x;
            sy = y < cy ? y : 2f * cy - y;
            break;
        default: // mirrorHorizontal
            sx = x < cx ? x : 2f * cx - x;
            sy = y;
            break;
    }

    var si = Math.Clamp((int)MathF.Round(sx), 0, size - 1);
    var sj = Math.Clamp((int)MathF.Round(sy), 0, size - 1);

    var (r, g, b, a) = input.GetPixel(si, sj);
    result.SetPixel(x, y, r, g, b, a);
});

return result;
}
